const raw = $json.body || $json;
const topic = raw.topic || raw.alert_id || ('infra-' + Date.now());
const voters = Array.isArray(raw.expected_voters) && raw.expected_voters.length > 0
  ? raw.expected_voters
  : ['infra_t3610', 'infra_gx10', 'infra_rpi'];
const votes = Array.isArray(raw.votes) ? raw.votes.map(v => ({
  actor: v.actor,
  vote: String(v.vote || '').toLowerCase(),
  topic,
  rationale: v.rationale || null
})) : [];
return [{ json: {
  topic,
  severity: raw.severity || 'unknown',
  summary: raw.summary || raw.message || '',
  votes,
  expected_voters: voters,
  vote_opened_at: raw.vote_opened_at || new Date().toISOString(),
  source: raw.source || 'infra-vote-broadcast'
}}];

const input = $input.item.json;
const env = (typeof process !== 'undefined' && process.env) ? process.env : {};
let rules = { quorum: 2, weights: { infra_t3610: 1, infra_gx10: 1, infra_rpi: 1 }, majority_threshold: 0.66, timeout_seconds: 900 };
let rulesStatus = 'default_embedded_from_repo_config';
const rulesRaw = env.VOTE_RULES_JSON || input.vote_rules_json || null;
if (rulesRaw) {
  try {
    rules = typeof rulesRaw === 'string' ? JSON.parse(rulesRaw) : rulesRaw;
    rulesStatus = 'loaded';
  } catch (e) {
    rulesStatus = 'parse_error:' + e.message;
  }
}
const votes = input.votes || [];
const tally = { approve: 0, reject: 0, abstain: 0 };
for (const v of votes) {
  const vote = String(v.vote || '').toLowerCase();
  if (vote in tally) tally[vote] += 1;
}
const quorum = Number.isFinite(Number(rules.quorum)) ? Number(rules.quorum) : null;
let result = 'pending';
let method = 'no_votes';
if (votes.length > 0 && quorum !== null && votes.length < quorum) {
  method = 'quorum_not_met';
} else if (votes.length > 0) {
  let weightedApprove = 0;
  let weightedReject = 0;
  const weights = rules.weights || {};
  for (const v of votes) {
    const weight = Number(weights[v.actor] ?? 1);
    if (v.vote === 'approve') weightedApprove += weight;
    if (v.vote === 'reject') weightedReject += weight;
  }
  const decisive = weightedApprove + weightedReject;
  if (decisive === 0) {
    method = 'all_abstained';
  } else {
    const threshold = Number.isFinite(Number(rules.majority_threshold)) ? Number(rules.majority_threshold) : 0.5;
    const approveRatio = weightedApprove / decisive;
    result = approveRatio > threshold ? 'approved' : 'rejected';
    method = 'threshold_' + threshold;
    input.weighted = { approve: weightedApprove, reject: weightedReject };
    input.approve_ratio = Math.round(approveRatio * 100) / 100;
  }
}
return [{ json: {
  ...input,
  result,
  method,
  tally,
  quorum_required: quorum,
  votes_received: votes.length,
  vote_rules_status: rulesStatus,
  vote_closed_at: new Date().toISOString()
}}];
